INSERT INTO quotes (body, source_media, writer) VALUES ('It has to start somewhere. It has to start sometime. What better place than here? What better time than now?', 'Guerilla Radio', 'Rage Against The Machine');
INSERT INTO quotes (body, source_media, writer) VALUES ('I would rather starve than eat your bread', 'Corduroy', 'Pearl Jam');
INSERT INTO quotes (body, source_media, writer) VALUES ('When the light comes big and bright, I began another life', 'Afterlife', 'Alex G');
INSERT INTO quotes (body, source_media, writer) VALUES ('I say love, don''t mean nothing, unless there''s something worth fighting for. It''s a beautful war', 'Beautiful War', 'Kings of Leon');
INSERT INTO quotes (body, source_media, writer) VALUES ('To live, and not to breathe, is to die, in tragedy', 'Jesus of Suburbia', 'Green Day');
INSERT INTO quotes (body, source_media, writer) VALUES ('We''ve got the vision, now let''s have some fun', 'Time to Pretend', 'MGMT');
INSERT INTO quotes (body, source_media, writer) VALUES ('You''ve been setting your own trap, and you''ll never make it back. You can''t shelter sorrow, you won''t be here tomorrow.', 'Self Trap', 'Playground Kings');
INSERT INTO quotes (body, source_media, writer) VALUES ('I''m not alone cuz'' the TV''s on. I''m not crazy cuz'' I take the right pills, everyday', 'Bleed American', 'Jimmy Eat World');
INSERT INTO quotes (body, source_media, writer) VALUES ('And in the darkest night, if my memory serves me right. I''ll never turn back time, forgetting you but not the time', 'Whatshername', 'Green Day');
INSERT INTO quotes (body, source_media, writer) VALUES ('Life goes on, long after the thrill of livin'' is gone', 'Jack & Diane', 'John Mellencamp');
INSERT INTO quotes (body, source_media, writer) VALUES ('If this is what you call the good life, I want a better way to die', 'Forever Now', 'Green Day');
INSERT INTO quotes (body, source_media, writer) VALUES ('I''m running late to somewhere now, that I don''t want to be. Where the future and promises ain''t what it used to be.', 'Forever Now', 'Green Day');
INSERT INTO quotes (body, source_media, writer) VALUES ('Cause I don''t care where I belong no more. What we share or not I will ignore. And I won''t waste my time fittin'' in. Cause I don''t think contrast is a sin. No it''s not a sin', 'No Cigar', 'Millencolin');
INSERT INTO quotes (body, source_media, writer) VALUES ('No one needs the sorrow, no one needs to pain. I hate to see you walkin'' out there, out in the rain', 'Rocket Queen', 'Guns N'' Roses');
INSERT INTO quotes (body, source_media, writer) VALUES ('Even new wine served in old skins, cheapens the taste', 'The No Seatbelt Song', 'Brand New');
INSERT INTO quotes (body, source_media, writer) VALUES ('Great words won''t cover ugly actions. Good frames won''t save bad paintings', 'New Noise', 'Refused');
INSERT INTO quotes (body, source_media, writer) VALUES ('At 23 I was far from feeling free. At 24, my life was a big bore. Now I''m 25 and I''m still not high. I''m 25 but still alive.', 'Right About Now', 'Millencolin');
INSERT INTO quotes (body, source_media, writer) VALUES ('Did I remember to keep your beer as full as mine, did I, did I remember to say cheers? Did I, did I, at least try to make sure everybody had a good time?', 'I''m Dying Tomorrow', 'Alkaline Trio');
INSERT INTO quotes (body, source_media, writer) VALUES ('There''s a boy who fogs his world, and now he''s getting lazy. There''s no motivation and frustration makes him crazy. He makes a plan to take a stand but always ends up sitting. Someone help him up or he is gonna end up quitting', 'Who Wrote Holden Caulfield?', 'Green Day');
INSERT INTO quotes (body, source_media, writer) VALUES ('I''d rather run the other way than stay and see, the smoke and who''s still standing when it clears', 'Over My Head (Cable Car)', 'The Fray');
INSERT INTO quotes (body, source_media, writer) VALUES ('If I am not for myself, who is for me? And if I am only for myself, what am I?', '', '');
INSERT INTO quotes (body, source_media, writer) VALUES ('Are you gonna stand around until 2012 AD? What are you waiting for, a certain shade of green? I think I grew a gray watching you procrastinate. What are you waiting for, a certain shade of green?', 'A Certain Shade of Green', 'Incubus');
INSERT INTO quotes (body, source_media, writer) VALUES ('Is all the world jails and churches?', 'Vietnow', 'Rage Against The Machine');
INSERT INTO quotes (body, source_media, writer) VALUES ('I don''t wanna waste my time, become another casualty of society. I''ll never fall in line, become a victim of your conformity and back down', 'Fat Lip', 'Sum 41');
INSERT INTO quotes (body, source_media, writer) VALUES ('When was it that you sold your life or wasted, every bite of that small slice you never tasted?', 'Mr. Chainsaw', 'Alkaline Trio');
